// ============================================
// Components - Playful Geometric Design
// ============================================

// Pill Badge with hard shadow
const Badge = ({ children, variant = 'default', className = '' }: { children: React.ReactNode; variant?: 'default' | 'outline' | 'ghost' | 'pink' | 'yellow' | 'mint'; className?: string }) => {
  const variants = {
    default: 'bg-orange-100 text-orange-600 border-2 border-orange-200',
    outline: 'bg-transparent text-slate-700 border-2 border-slate-300',
    ghost: 'bg-transparent text-slate-500 border-2 border-transparent',
    pink: 'bg-pink-100 text-pink-600 border-2 border-pink-200',
    yellow: 'bg-yellow-100 text-yellow-600 border-2 border-yellow-200',
    mint: 'bg-emerald-100 text-emerald-600 border-2 border-emerald-200',
  };
  
  return (
    <span className={`inline-flex items-center gap-1.5 px-4 py-2 text-sm font-semibold rounded-full transition-all duration-200 hover:scale-105 ${variants[variant]} ${className}`}>
      {children}
    </span>
  );
};

// Candy Button with hard shadow
const Button = ({ 
  children, 
  variant = 'primary', 
  size = 'md',
  className = '',
  icon: Icon,
  onClick
}: { 
  children: React.ReactNode; 
  variant?: 'primary' | 'secondary' | 'ghost' | 'outline' | 'white';
  size?: 'sm' | 'md' | 'lg';
  className?: string;
  icon?: React.ComponentType<{ className?: string }>;
  onClick?: () => void;
}) => {
  const baseStyles = 'inline-flex items-center justify-center gap-2 font-bold transition-all duration-200 rounded-full';
  const variants = {
    primary: 'bg-orange-500 text-white border-2 border-slate-800 shadow-hard hover:shadow-hard-hover hover:-translate-y-1 active:shadow-hard-active active:translate-y-0',
    secondary: 'bg-white text-slate-800 border-2 border-slate-300 shadow-hard-sm hover:shadow-hard hover:-translate-y-1 active:shadow-hard-sm active:translate-y-0',
    ghost: 'bg-transparent text-slate-600 hover:bg-slate-100 border-2 border-transparent',
    outline: 'bg-transparent text-slate-800 border-2 border-slate-400 hover:border-slate-800 hover:bg-slate-50',
    white: 'bg-white text-slate-800 border-2 border-slate-200 shadow-hard-sm hover:shadow-hard hover:-translate-y-1',
  };
  const sizes = {
    sm: 'px-5 py-2.5 text-sm',
    md: 'px-7 py-3 text-sm',
    lg: 'px-9 py-4 text-base',
  };
  
  return (
    <button onClick={onClick} className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}>
      {children}
      {Icon && <Icon className="w-4 h-4" />}
    </button>
  );
};

// Sticker Card with hard shadow and wiggle
const Card = ({ children, className = '', hover = false, featured = false }: { children: React.ReactNode; className?: string; hover?: boolean; featured?: boolean }) => (
  <div className={`bg-white rounded-2xl border-2 border-slate-800 ${featured ? 'shadow-hard-accent' : 'shadow-hard-sm'} ${hover ? 'hover:shadow-hard hover:-translate-y-2 animate-wiggle-hover' : ''} transition-all duration-200 ${className}`}>
    {children}
  </div>
);
